#include <bits/stdc++.h>
using namespace std;

const int N=5e4+10;

int pr[N],cnt,mu[N],s[N],f[N],p[N];
long long sf[N];
bool np[N];
int T,n,m;

void init(){
    np[0]=np[1]=1;
    mu[1]=1,f[1]=1;
    for(int i=2;i<N;i++){
        if(!np[i]) mu[i]=-1,f[i]=2,p[i]=1,pr[++cnt]=i;
        for(int j=1;1ll*pr[j]*i<N;j++){
            np[pr[j]*i]=1;
            if(i%pr[j]==0){
                p[pr[j]*i]=p[i]+1;
                f[pr[j]*i]=f[i]/(p[i]+1)*(p[i]+2);
                break;
            }
            mu[pr[j]*i]=-mu[i];
            p[pr[j]*i]=1;
            f[pr[j]*i]=f[i]*2;
        }
    }
    for(int i=1;i<N;i++){
        s[i]=s[i-1]+mu[i];
        sf[i]=sf[i-1]+f[i];
    }
}

int main(){
    init();
    scanf("%d",&T);
    while(T--){
        scanf("%d%d",&n,&m);
        long long ans=0;
        if(n>m) swap(n,m);
        for(int l=1,r;l<=n;l=r+1){
            r=min(n/(n/l),m/(m/l));
            ans=ans+1ll*(s[r]-s[l-1])*sf[n/l]*sf[m/l];
        }
        printf("%lld\n",ans);
    }
    return 0;
}
